1879	export function makeRecessedWallMesh(
1880	  wall: WallElem,
1881	  elevM: number,
1882	  paint: ViewportPaintBundle | null,
1883	  roofForSlope?: Extract<Element, { kind: 'roof' }> | null,
1884	  elementsById?: Record<string, Element>,
1885	): THREE.Group {
1886	  const halfThickM = THREE.MathUtils.clamp(wall.thicknessMm / 1000, 0.05, 2) / 2;
1887	
1888	  // Sort recess zones by alongTStart so we walk them in order.
1889	  const zones = [...(wall.recessZones ?? [])].sort((a, b) => a.alongTStart - b.alongTStart);
1890	
1891	  // Build exterior path (plan space, mm). Starts at start exterior, walks
1892	  // Build a multi-box group: full-thickness end caps for each non-recessed
1893	  // span, plus a back-wall box for each recess zone. This avoids the
1894	  // self-intersecting polygon problem of trying to extrude a single
1895	  // closed contour with cheek-wall + back-wall arches.
1896	  const baseOff = (wall.baseConstraintOffsetMm ?? 0) / 1000;
1897	  const yBase = elevM + baseOff;
1898	  const height = THREE.MathUtils.clamp(wall.heightMm / 1000, 0.25, 40);
1899	
1900	  const wallMatSpec = resolveMaterial(wall.materialKey);
1901	  const isWhite = wall.materialKey === 'white_cladding' || wall.materialKey === 'white_render';
1902	  const wallBaseColor =
1903	    wallMatSpec?.baseColor ?? (isWhite ? '#f4f4f0' : categoryColorOr(paint, 'wall'));
1904	  const mat = new THREE.MeshStandardMaterial({
1905	    color: wallBaseColor,
1906	    roughness:
1907	      wallMatSpec?.roughness ?? (isWhite ? 0.92 : (paint?.categories.wall.roughness ?? 0.85)),
1908	    metalness: wallMatSpec?.metalness ?? paint?.categories.wall.metalness ?? 0.0,
1909	    // Cladding / render walls drop sky-reflection so the catalog colour
1910	    // reads true (warm wood as warm wood, not pale-blue from sky env map).
1911	    envMapIntensity:
1912	      isWhite || wallMatSpec?.category === 'render' || wallMatSpec?.category === 'cladding'
1913	        ? 0.15
1914	        : 1.0,
1915	  });
1916	
1917	  // White-render variant for end caps when the wall's primary materialKey
1918	  // is the recess back finish (cladding_warm_wood). Approximates the
1919	  // architectural "white frame around a wood-clad recess" pattern.
1920	  const capMat =
1921	    wall.materialKey === 'cladding_warm_wood'
1922	      ? new THREE.MeshStandardMaterial({
1923	          color: '#f4f4f0',
1924	          roughness: 0.92,
1925	          metalness: 0,
1926	          envMapIntensity: 0.15,
1927	        })
1928	      : mat;
1929	
1930	  const group = new THREE.Group();
1931	  group.userData.bimPickId = wall.id;
1932	
1933	  // Compute non-recessed spans (full-thickness wall segments) and recessed
1934	  // spans (where the wall plane has stepped back). Each becomes its own
1935	  // axis-aligned box at the wall's yaw rotation.
1936	  const yaw = Math.atan2(wall.end.yMm - wall.start.yMm, wall.end.xMm - wall.start.xMm);
1937	  const wallLenM = Math.hypot(wall.end.xMm - wall.start.xMm, wall.end.yMm - wall.start.yMm) / 1000;
1938	  const wallCx = (wall.start.xMm + wall.end.xMm) / 2 / 1000;
1939	  const wallCz = (wall.start.yMm + wall.end.yMm) / 2 / 1000;
1940	
1941	  // Plan unit vectors for sampling roof at recessed positions. Direction
1942	  // is start→end; interior normal is rotated 90° CCW from direction.
1943	  const planDirX = wallLenM > 0 ? (wall.end.xMm - wall.start.xMm) / (wallLenM * 1000) : 1;
1944	  const planDirY = wallLenM > 0 ? (wall.end.yMm - wall.start.yMm) / (wallLenM * 1000) : 0;
1945	  const planNormX = -planDirY;
1946	  const planNormY = planDirX;
1947	
1948	  function addBoxAt(t0: number, t1: number, perpMmOffset: number, material: THREE.Material) {
1949	    const segLen = (t1 - t0) * wallLenM;
1950	    if (segLen < 1e-4) return;
1951	    const segMid = (t0 + t1) / 2;
1952	    // Centre offset along wall direction:
1953	    //   centre_along = (segMid - 0.5) * len
1954	    // Then rotate by yaw to get world XZ contribution.
1955	    const along = (segMid - 0.5) * wallLenM;
1956	    // Perpendicular offset in plan-space (interior normal direction) → world
1957	    // XZ. Plan-Y maps directly to world-Z under the viewport convention.
