/** @typedef {Record<string, unknown>} BimCommand */

/*
 * Canonical seed: the demo "one-family home" project.
 *
 * Authored phase-by-phase per `claude-skills/sketch-to-bim/SKILL.md`.
 * Reference spec: `spec/target-house-seed.md`.
 * Visual ground-truth: `spec/target-house-seed-vis.png` (line sketch)
 *                      `spec/target-house-vis-colored.png` (colour study, 4 panels).
 *
 * Coordinate convention (plan):
 *   +xMm = east, +yMm = north (south facade sits at y = 0)
 *   zMm / levelElevation = height above ground slab
 */

// ── Dimensional constants ─────────────────────────────────────────────
const GF_W = 7000; // ground-floor east-west width
const GF_D = 8000; // building depth north-south (both floors)
const UF_W = 5000; // upper-floor east-west width (west-aligned)
const F2F = 3000; // floor-to-floor height (ground → upper)
const WALL_T = 250; // exterior wall thickness

// Near-symmetric asymmetric gable — ridge at 60 % of UF width from west
// (spec §1.2 "roughly 60 % of the upper-volume width from the west edge").
// West eave slightly lower than east; both pitches similar (~25–30°).
const EAVE_W = 1500; // west (low) eave height above UF slab, mm
const EAVE_E = 2300; // east (high) eave height above UF slab, mm
const RIDGE_OFFS = 500; // ridge X-offset east of UF centre → x = 3 000 mm from west

// Computed gable geometry (ridgeAlongX = false — UF is 5 000 < 8 000 mm depth):
//   leftRun  = UF_W/2 + RIDGE_OFFS = 3 000 mm  (west edge → ridge)
//   RIDGE_H  = EAVE_W + leftRun · tan(30°) = 1 500 + 1 732 = 3 232 mm above UF
//   rightRun = UF_W/2 − RIDGE_OFFS = 2 000 mm  (ridge → east edge)
//   eastPitch = atan(932 / 2 000) ≈ 25°          (west 30°, east 25° — near-symmetric ✓)
const SLOPE_DEG = 30;
const LEFT_RUN = UF_W / 2 + RIDGE_OFFS; // 3 000 mm
const RIDGE_H = Math.round(EAVE_W + LEFT_RUN * Math.tan((SLOPE_DEG * Math.PI) / 180)); // 3 232 mm

// Absolute Z coordinates (above ground slab = 0)
const UF_Z = F2F; // 3 000 mm
const EAVE_W_Z = UF_Z + EAVE_W; // 4 500 mm  (west eave absolute)
const EAVE_E_Z = UF_Z + EAVE_E; // 5 300 mm  (east eave absolute)
const RIDGE_Z = UF_Z + RIDGE_H; // 6 232 mm  (ridge absolute)
const RIDGE_X = UF_W / 2 + RIDGE_OFFS; // 3 000 mm from west edge

// UF wall height before roof-attachment crop. Must exceed RIDGE_H; 3 800 mm
// is ridge + 568 mm headroom — walls get cropped to the gable profile.
const UF_WALL_H = RIDGE_H + 568; // 3 800 mm

const PARAPET_H = 200; // east deck parapet height above UF slab
const LOGGIA_SETBACK = 1500; // loggia recess depth south → north (spec §1.4 ~1 500 mm)
const BALCONY_PROJ = 650; // balcony projection south of facade plane (spec §1.4 "very slightly")

/**
 * @returns {BimCommand[]}
 */
export function buildOneFamilyHomeCommands() {
  return [
    // ── Project base point + levels ───────────────────────────────────
    {
      type: 'createProjectBasePoint',
      id: 'hf-pbp',
      positionMm: { xMm: 0, yMm: 0, zMm: 0 },
      angleToTrueNorthDeg: 0,
    },
    { type: 'createLevel', id: 'hf-lvl-ground', name: 'Ground Floor', elevationMm: 0 },
    { type: 'createLevel', id: 'hf-lvl-upper', name: 'First Floor', elevationMm: F2F },

    // === PHASE 1: MASSING ===
    // Three volumetric blocks — ground floor base (7 000 × 8 000), upper
    // west-aligned volume (5 000 × 8 000), and the east-deck parapet strip
    // (2 000 × 8 000). Deleted at the start of Phase 2 (mass-box roofs
    // at z = 3 000 would z-fight the upper-floor + deck slabs).
    {
      type: 'createMass',
      id: 'hf-mass-gf',
      name: 'Ground floor mass',
      levelId: 'hf-lvl-ground',
      footprintMm: [
        { xMm: 0, yMm: 0 },
        { xMm: GF_W, yMm: 0 },
        { xMm: GF_W, yMm: GF_D },
        { xMm: 0, yMm: GF_D },
      ],
      heightMm: F2F,
      materialKey: 'cladding_beige_grey',
    },
    {
      type: 'createMass',
      id: 'hf-mass-uf',
      name: 'Upper floor mass (west-aligned)',
      levelId: 'hf-lvl-upper',
      footprintMm: [
        { xMm: 0, yMm: 0 },
        { xMm: UF_W, yMm: 0 },
        { xMm: UF_W, yMm: GF_D },
        { xMm: 0, yMm: GF_D },
      ],
      heightMm: EAVE_E, // east eave height as placeholder
      materialKey: 'white_render',
    },
    {
      type: 'createMass',
      id: 'hf-mass-parapet',
      name: 'East deck parapet mass',
      levelId: 'hf-lvl-upper',
      footprintMm: [
        { xMm: UF_W, yMm: 0 },
        { xMm: GF_W, yMm: 0 },
        { xMm: GF_W, yMm: GF_D },
        { xMm: UF_W, yMm: GF_D },
      ],
      heightMm: PARAPET_H,
      materialKey: 'cladding_beige_grey',
    },

    // === PHASE 2: SKELETON ===
    // Delete Phase 1 masses, build load-bearing structural primitives:
    // perimeter walls at every level + floor slabs + flat-roof placeholder.
    { type: 'deleteElement', elementId: 'hf-mass-gf' },
    { type: 'deleteElement', elementId: 'hf-mass-uf' },
    { type: 'deleteElement', elementId: 'hf-mass-parapet' },

    // Ground-floor perimeter walls (height = F2F, CCW from SW corner).
    {
      type: 'createWall',
      id: 'hf-w-gf-s',
      name: 'GF south wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: 0, yMm: 0 },
      end: { xMm: GF_W, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: F2F,
    },
    {
      type: 'createWall',
      id: 'hf-w-gf-e',
      name: 'GF east wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: GF_W, yMm: 0 },
      end: { xMm: GF_W, yMm: GF_D },
      thicknessMm: WALL_T,
      heightMm: F2F,
    },
    {
      type: 'createWall',
      id: 'hf-w-gf-n',
      name: 'GF north wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: GF_W, yMm: GF_D },
      end: { xMm: 0, yMm: GF_D },
      thicknessMm: WALL_T,
      heightMm: F2F,
    },
    {
      type: 'createWall',
      id: 'hf-w-gf-w',
      name: 'GF west wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: 0, yMm: GF_D },
      end: { xMm: 0, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: F2F,
    },

    // Upper-floor perimeter walls (5 000 × 8 000, west-aligned).
    // heightMm = UF_WALL_H (ridge + margin) — Phase 3 crops to the
    // asymmetric gable profile via attachWallTopToRoof.
    {
      type: 'createWall',
      id: 'hf-w-uf-s',
      name: 'UF south wall',
      levelId: 'hf-lvl-upper',
      start: { xMm: 0, yMm: 0 },
      end: { xMm: UF_W, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: UF_WALL_H,
    },
    {
      type: 'createWall',
      id: 'hf-w-uf-e',
      name: 'UF east wall',
      levelId: 'hf-lvl-upper',
      start: { xMm: UF_W, yMm: 0 },
      end: { xMm: UF_W, yMm: GF_D },
      thicknessMm: WALL_T,
      heightMm: UF_WALL_H,
    },
    {
      type: 'createWall',
      id: 'hf-w-uf-n',
      name: 'UF north wall',
      levelId: 'hf-lvl-upper',
      start: { xMm: UF_W, yMm: GF_D },
      end: { xMm: 0, yMm: GF_D },
      thicknessMm: WALL_T,
      heightMm: UF_WALL_H,
    },
    {
      type: 'createWall',
      id: 'hf-w-uf-w',
      name: 'UF west wall',
      levelId: 'hf-lvl-upper',
      start: { xMm: 0, yMm: GF_D },
      end: { xMm: 0, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: UF_WALL_H,
    },

    // East deck parapet walls (S / E / N — west edge butts UF east wall).
    {
      type: 'createWall',
      id: 'hf-w-pa-s',
      name: 'Deck parapet south',
      levelId: 'hf-lvl-upper',
      start: { xMm: UF_W, yMm: 0 },
      end: { xMm: GF_W, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: PARAPET_H,
    },
    {
      type: 'createWall',
      id: 'hf-w-pa-e',
      name: 'Deck parapet east',
      levelId: 'hf-lvl-upper',
      start: { xMm: GF_W, yMm: 0 },
      end: { xMm: GF_W, yMm: GF_D },
      thicknessMm: WALL_T,
      heightMm: PARAPET_H,
    },
    {
      type: 'createWall',
      id: 'hf-w-pa-n',
      name: 'Deck parapet north',
      levelId: 'hf-lvl-upper',
      start: { xMm: GF_W, yMm: GF_D },
      end: { xMm: UF_W, yMm: GF_D },
      thicknessMm: WALL_T,
      heightMm: PARAPET_H,
    },

    // Floor slabs.
    {
      type: 'createFloor',
      id: 'hf-flr-ground',
      name: 'Ground floor slab',
      levelId: 'hf-lvl-ground',
      boundaryMm: [
        { xMm: 0, yMm: 0 },
        { xMm: GF_W, yMm: 0 },
        { xMm: GF_W, yMm: GF_D },
        { xMm: 0, yMm: GF_D },
      ],
    },
    {
      type: 'createFloor',
      id: 'hf-flr-upper',
      name: 'Upper floor slab (west)',
      levelId: 'hf-lvl-upper',
      boundaryMm: [
        { xMm: 0, yMm: 0 },
        { xMm: UF_W, yMm: 0 },
        { xMm: UF_W, yMm: GF_D },
        { xMm: 0, yMm: GF_D },
      ],
    },
    {
      type: 'createFloor',
      id: 'hf-flr-deck',
      name: 'East roof-terrace deck',
      levelId: 'hf-lvl-upper',
      boundaryMm: [
        { xMm: UF_W, yMm: 0 },
        { xMm: GF_W, yMm: 0 },
        { xMm: GF_W, yMm: GF_D },
        { xMm: UF_W, yMm: GF_D },
      ],
    },

    // Flat-roof placeholder on UF — Phase 3 replaces with asymmetric_gable.
    {
      type: 'createRoof',
      id: 'hf-roof-main',
      name: 'Upper-volume roof (placeholder flat)',
      referenceLevelId: 'hf-lvl-upper',
      footprintMm: [
        { xMm: 0, yMm: 0 },
        { xMm: UF_W, yMm: 0 },
        { xMm: UF_W, yMm: GF_D },
        { xMm: 0, yMm: GF_D },
      ],
      roofGeometryMode: 'flat',
      slopeDeg: 0,
      overhangMm: 0,
    },

    // === PHASE 3: ENVELOPE ===
    // Replace the flat placeholder with the near-symmetric asymmetric_gable.
    // updateElementProperty only supports roofTypeId|roofGeometryMode|name;
    // asymmetric_gable needs new fields so we delete + recreate.
    { type: 'deleteElement', elementId: 'hf-roof-main' },
    {
      type: 'createRoof',
      id: 'hf-roof-main',
      name: 'Upper-volume asymmetric gable',
      referenceLevelId: 'hf-lvl-upper',
      footprintMm: [
        { xMm: 0, yMm: 0 },
        { xMm: UF_W, yMm: 0 },
        { xMm: UF_W, yMm: GF_D },
        { xMm: 0, yMm: GF_D },
      ],
      roofGeometryMode: 'asymmetric_gable',
      // Ridge runs N–S (ridgeAlongX = false because spanX=5 000 < spanZ=8 000).
      // Offset 500 mm east of UF centre → ridge at x = 3 000 mm from west.
      // Slope sanity: RIDGE_H = 1 500 + 3 000·tan(30°) = 3 232 mm > EAVE_E = 2 300 ✓
      ridgeOffsetTransverseMm: RIDGE_OFFS,
      eaveHeightLeftMm: EAVE_W,
      eaveHeightRightMm: EAVE_E,
      slopeDeg: SLOPE_DEG,
      overhangMm: 0,
      materialKey: 'metal_standing_seam_dark_grey',
    },

    // Attach UF walls to the gable so their tops crop along the slope.
    // South + north walls (gable ends) get the full triangular crown.
    // East + west walls (eave sides) get a uniform flat crop at their eave height.
    { type: 'attachWallTopToRoof', wallId: 'hf-w-uf-s', roofId: 'hf-roof-main' },
    { type: 'attachWallTopToRoof', wallId: 'hf-w-uf-e', roofId: 'hf-roof-main' },
    { type: 'attachWallTopToRoof', wallId: 'hf-w-uf-n', roofId: 'hf-roof-main' },
    { type: 'attachWallTopToRoof', wallId: 'hf-w-uf-w', roofId: 'hf-roof-main' },

    // Fix for north gable-end rendering: makeSlopedWallMesh only samples the
    // two endpoints, giving a flat diagonal top instead of the triangular crown.
    // A minimal recessZone triggers makeRecessedWallMesh, which samples 25 steps
    // and correctly resolves the ridge peak. 50 mm setback is imperceptible
    // at normal viewing distances but fixes the rear-axonometric silhouette.
    {
      type: 'setWallRecessZones',
      wallId: 'hf-w-uf-n',
      recessZones: [{ alongTStart: 0.0, alongTEnd: 1.0, setbackMm: 50, floorContinues: false }],
    },

    // Exterior material keys.
    {
      type: 'updateElementProperty',
      elementId: 'hf-w-gf-s',
      key: 'materialKey',
      value: 'cladding_beige_grey',
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-w-gf-e',
      key: 'materialKey',
      value: 'cladding_beige_grey',
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-w-gf-n',
      key: 'materialKey',
      value: 'cladding_beige_grey',
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-w-gf-w',
      key: 'materialKey',
      value: 'cladding_beige_grey',
    },
    // UF south wall → cladding_warm_wood: the recess back wall (loggia interior)
    // renders with this material; the Phase 3 picture-frame sweep forms the
    // white gable outline on the exterior facade.
    {
      type: 'updateElementProperty',
      elementId: 'hf-w-uf-s',
      key: 'materialKey',
      value: 'cladding_warm_wood',
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-w-uf-e',
      key: 'materialKey',
      value: 'white_render',
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-w-uf-n',
      key: 'materialKey',
      value: 'white_render',
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-w-uf-w',
      key: 'materialKey',
      value: 'white_render',
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-w-pa-s',
      key: 'materialKey',
      value: 'cladding_beige_grey',
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-w-pa-e',
      key: 'materialKey',
      value: 'cladding_beige_grey',
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-w-pa-n',
      key: 'materialKey',
      value: 'cladding_beige_grey',
    },

    // Picture-frame outline (KRN-15 sweep) — traces the south-face gable
    // pentagon at the facade plane (yMm = 0). The planar-frame fast path in
    // sweepMesh.ts detects this constant-yMm closed loop and builds a clean
    // ExtrudeGeometry ring without parallel-transport corner artefacts.
    //
    // Path vertices in plan (xMm, yMm=0, zMm=absolute height):
    //   SW corner (x=0,      z=UF_Z=3000) →
    //   SE corner (x=UF_W,   z=UF_Z=3000) →
    //   E eave    (x=UF_W,   z=EAVE_E_Z=5300) →
    //   Ridge     (x=RIDGE_X,z=RIDGE_Z=6232) →
    //   W eave    (x=0,      z=EAVE_W_Z=4500) →
    //   close at SW.
    //
    // Profile: uMm = depth proud of facade (160 mm total),
    //          vMm = frame band width (600 mm total — ~12 % of UF_W per side).
    {
      type: 'createSweep',
      id: 'hf-sw-frame',
      name: 'Gable picture-frame',
      levelId: 'hf-lvl-ground',
      pathMm: [
        { xMm: 0, yMm: 0, zMm: UF_Z },
        { xMm: UF_W, yMm: 0, zMm: UF_Z },
        { xMm: UF_W, yMm: 0, zMm: EAVE_E_Z },
        { xMm: RIDGE_X, yMm: 0, zMm: RIDGE_Z },
        { xMm: 0, yMm: 0, zMm: EAVE_W_Z },
        { xMm: 0, yMm: 0, zMm: UF_Z },
      ],
      profileMm: [
        { uMm: -80, vMm: -300 },
        { uMm: 80, vMm: -300 },
        { uMm: 80, vMm: 300 },
        { uMm: -80, vMm: 300 },
      ],
      profilePlane: 'work_plane',
      materialKey: 'white_render',
    },

    // === PHASE 4: OPENINGS ===

    // GF south facade: 2 portrait windows (left half) + 1 front door (right-of-centre)
    // + 1 small vertical window on the east extension (spec §1.3 & §1.6).
    {
      type: 'insertWindowOnWall',
      id: 'hf-win-gf-s-l1',
      name: 'GF south window (left)',
      wallId: 'hf-w-gf-s',
      alongT: 0.1,
      widthMm: 700,
      heightMm: 1800,
      sillHeightMm: 200,
    },
    {
      type: 'insertWindowOnWall',
      id: 'hf-win-gf-s-l2',
      name: 'GF south window (centre-left)',
      wallId: 'hf-w-gf-s',
      alongT: 0.22,
      widthMm: 700,
      heightMm: 1800,
      sillHeightMm: 200,
    },
    {
      type: 'insertDoorOnWall',
      id: 'hf-door-front',
      name: 'Front door',
      wallId: 'hf-w-gf-s',
      alongT: 0.55,
      widthMm: 900,
    },
    // East extension small window at x ≈ 5 950 mm (alongT 0.85 of 7 000 mm).
    {
      type: 'insertWindowOnWall',
      id: 'hf-win-ext-s',
      name: 'East extension south window',
      wallId: 'hf-w-gf-s',
      alongT: 0.85,
      widthMm: 600,
      heightMm: 1200,
      sillHeightMm: 1000,
    },

    // Loggia recess on UF south wall — full-width so the warm-wood back wall
    // fills the entire pentagon interior (spec §1.4 "everything inside this
    // white frame is set back"). The picture-frame sweep forms the white border.
    {
      type: 'setWallRecessZones',
      wallId: 'hf-w-uf-s',
      recessZones: [
        { alongTStart: 0.0, alongTEnd: 1.0, setbackMm: LOGGIA_SETBACK, floorContinues: true },
      ],
    },

    // Loggia openings — hosted on hf-w-uf-s; renderer offsets them to the
    // recessed back surface (KRN-16 recessOffsetForOpening convention).
    //
    // Right: large floor-to-ceiling sliding glass door (spec §1.4).
    {
      type: 'insertDoorOnWall',
      id: 'hf-door-loggia',
      name: 'Loggia sliding door',
      wallId: 'hf-w-uf-s',
      alongT: 0.68,
      widthMm: 1800,
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-door-loggia',
      key: 'operationType',
      value: 'sliding_double',
    },

    // Left: trapezoidal window whose top follows the west gable pitch (spec §1.4
    // "smaller trapezoidal window on the left whose top edge slopes to follow
    // the long, low angle of the roof pitch"). KRN-12 gable_trapezoid outline.
    {
      type: 'insertWindowOnWall',
      id: 'hf-win-loggia-trap',
      name: 'Loggia trapezoidal window',
      wallId: 'hf-w-uf-s',
      alongT: 0.18,
      widthMm: 1600,
      heightMm: 2000,
      sillHeightMm: 200,
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-win-loggia-trap',
      key: 'outlineKind',
      value: 'gable_trapezoid',
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-win-loggia-trap',
      key: 'attachedRoofId',
      value: 'hf-roof-main',
    },

    // UF east wall: floor-to-ceiling sliding doors opening onto the east deck
    // (spec §1.6 "large floor-to-ceiling sliding glass doors … onto the east deck").
    // No dormer cut — spec/target-house-seed.md §1.6 explicitly retires the
    // "massive rectangular dormer cut-out"; the gable roof is uninterrupted.
    {
      type: 'insertDoorOnWall',
      id: 'hf-door-deck',
      name: 'East deck sliding doors',
      wallId: 'hf-w-uf-e',
      alongT: 0.38,
      widthMm: 2400,
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-door-deck',
      key: 'operationType',
      value: 'sliding_double',
    },

    // === PHASE 5: INTERIOR ===
    // Open-plan ground floor. Upper floor: 2 bedrooms + bathroom separated
    // by a mid-depth E-W partition and a N-S partition in the north half.
    {
      type: 'createWall',
      id: 'hf-w-uf-ptn-ew',
      name: 'UF mid partition (E-W)',
      levelId: 'hf-lvl-upper',
      start: { xMm: 0, yMm: 4000 },
      end: { xMm: UF_W, yMm: 4000 },
      thicknessMm: 120,
      heightMm: 2700,
    },
    {
      type: 'createWall',
      id: 'hf-w-uf-ptn-ns',
      name: 'UF back partition (N-S)',
      levelId: 'hf-lvl-upper',
      start: { xMm: 2500, yMm: 4000 },
      end: { xMm: 2500, yMm: GF_D },
      thicknessMm: 120,
      heightMm: 2700,
    },

    // Main stair: straight run, ground → upper. Positioned east of centre
    // in the GF (staircase silhouette faintly visible through south windows).
    {
      type: 'createStair',
      id: 'hf-stair-main',
      name: 'Main stair',
      baseLevelId: 'hf-lvl-ground',
      topLevelId: 'hf-lvl-upper',
      runStartMm: { xMm: 4200, yMm: 3000 },
      runEndMm: { xMm: 4200, yMm: 6500 },
      widthMm: 1000,
      riserMm: 175,
      treadMm: 220,
    },

    // Stair shaft opening in the upper-floor slab.
    {
      type: 'createSlabOpening',
      id: 'hf-slab-stair',
      name: 'Stair shaft opening',
      hostFloorId: 'hf-flr-upper',
      boundaryMm: [
        { xMm: 3700, yMm: 3000 },
        { xMm: 4700, yMm: 3000 },
        { xMm: 4700, yMm: 6500 },
        { xMm: 3700, yMm: 6500 },
      ],
      isShaft: true,
    },

    // Stair railing along the open west side of the stair run.
    {
      type: 'createRailing',
      id: 'hf-rail-stair',
      name: 'Stair railing',
      hostedStairId: 'hf-stair-main',
      pathMm: [
        { xMm: 3700, yMm: 3000 },
        { xMm: 3700, yMm: 6500 },
      ],
    },

    // Room outlines.
    {
      type: 'createRoomOutline',
      id: 'hf-room-living',
      name: 'Open-plan kitchen + living',
      levelId: 'hf-lvl-ground',
      outlineMm: [
        { xMm: 200, yMm: 200 },
        { xMm: GF_W - 200, yMm: 200 },
        { xMm: GF_W - 200, yMm: GF_D - 200 },
        { xMm: 200, yMm: GF_D - 200 },
      ],
      programmeCode: 'living',
      targetAreaM2: 56,
    },
    {
      type: 'createRoomOutline',
      id: 'hf-room-bed1',
      name: 'Bedroom 1 (master)',
      levelId: 'hf-lvl-upper',
      outlineMm: [
        { xMm: 200, yMm: 200 },
        { xMm: UF_W - 200, yMm: 200 },
        { xMm: UF_W - 200, yMm: 3900 },
        { xMm: 200, yMm: 3900 },
      ],
      programmeCode: 'bedroom',
      targetAreaM2: 18,
    },
    {
      type: 'createRoomOutline',
      id: 'hf-room-bed2',
      name: 'Bedroom 2',
      levelId: 'hf-lvl-upper',
      outlineMm: [
        { xMm: 200, yMm: 4100 },
        { xMm: 2400, yMm: 4100 },
        { xMm: 2400, yMm: GF_D - 200 },
        { xMm: 200, yMm: GF_D - 200 },
      ],
      programmeCode: 'bedroom',
      targetAreaM2: 12,
    },
    {
      type: 'createRoomOutline',
      id: 'hf-room-bath',
      name: 'Bathroom',
      levelId: 'hf-lvl-upper',
      outlineMm: [
        { xMm: 2600, yMm: 4100 },
        { xMm: UF_W - 200, yMm: 4100 },
        { xMm: UF_W - 200, yMm: GF_D - 200 },
        { xMm: 2600, yMm: GF_D - 200 },
      ],
      programmeCode: 'bathroom',
      targetAreaM2: 6,
    },
    {
      type: 'createRoomOutline',
      id: 'hf-room-deck',
      name: 'East roof terrace',
      levelId: 'hf-lvl-upper',
      outlineMm: [
        { xMm: UF_W + 200, yMm: 200 },
        { xMm: GF_W - 200, yMm: 200 },
        { xMm: GF_W - 200, yMm: GF_D - 200 },
        { xMm: UF_W + 200, yMm: GF_D - 200 },
      ],
      programmeCode: 'terrace',
      targetAreaM2: 16,
    },

    // === PHASE 6: DETAIL ===
    // Loggia balcony projecting south from the UF south wall (spec §1.4
    // "projects very slightly forward, frameless transparent glass balustrade").
    {
      type: 'createBalcony',
      id: 'hf-balcony-loggia',
      name: 'Loggia balcony',
      wallId: 'hf-w-uf-s',
      elevationMm: F2F,
      projectionMm: BALCONY_PROJ,
      slabThicknessMm: 150,
      balustradeHeightMm: 1100,
    },

    // === PHASE 7: DOCUMENTATION ===
    // Named camera presets matching the four panels of target-house-vis-colored.png.
    // Building bbox: x ∈ [0, 7 000], y ∈ [0, 8 000], z ∈ [0, 6 232].
    // Centre: (3 500, 4 000, 3 116). Camera targets aimed at upper-volume mid-height
    // (z ≈ 4 800) so the gable + loggia occupy the frame centre.
    {
      type: 'saveViewpoint',
      id: 'vp-main-iso',
      name: 'Main isometric (SSW)',
      mode: 'orbit_3d',
      // SSW: camera ≈ 25° west of due south, elevation ≈ 30°. Horizontal
      // distance to target ≈ 13 000 mm → camera z = target_z + 13000·tan(30°) ≈ 4800 + 7505.
      camera: {
        position: { xMm: -1500, yMm: -8000, zMm: 12000 },
        target: { xMm: 3500, yMm: 4000, zMm: 4800 },
        up: { xMm: 0, yMm: 0, zMm: 1 },
      },
    },
    {
      type: 'saveViewpoint',
      id: 'vp-front-elev',
      name: 'Front elevation (south)',
      mode: 'orbit_3d',
      camera: {
        position: { xMm: 3500, yMm: -14000, zMm: 4800 },
        target: { xMm: 3500, yMm: 4000, zMm: 4800 },
        up: { xMm: 0, yMm: 0, zMm: 1 },
      },
    },
    {
      type: 'saveViewpoint',
      id: 'vp-side-elev-east',
      name: 'Side elevation (east)',
      mode: 'orbit_3d',
      camera: {
        position: { xMm: 20000, yMm: 4000, zMm: 4800 },
        target: { xMm: 3500, yMm: 4000, zMm: 4800 },
        up: { xMm: 0, yMm: 0, zMm: 1 },
      },
    },
    {
      type: 'saveViewpoint',
      id: 'vp-rear-axo',
      name: 'Rear axonometric (NE)',
      mode: 'orbit_3d',
      camera: {
        position: { xMm: 12000, yMm: 16000, zMm: 12000 },
        target: { xMm: 3500, yMm: 4000, zMm: 4800 },
        up: { xMm: 0, yMm: 0, zMm: 1 },
      },
    },

    // Plan views for both levels.
    {
      type: 'upsertPlanView',
      id: 'hf-pv-ground',
      name: 'GF plan',
      levelId: 'hf-lvl-ground',
    },
    {
      type: 'upsertPlanView',
      id: 'hf-pv-upper',
      name: 'First-floor plan',
      levelId: 'hf-lvl-upper',
    },

    // Section cut through the loggia at y = 2 000 — exposes the gable
    // profile, recess depth, and balcony in section.
    {
      type: 'createSectionCut',
      id: 'hf-sec-loggia',
      name: 'South-facade section through loggia',
      lineStartMm: { xMm: 0, yMm: 2000 },
      lineEndMm: { xMm: GF_W, yMm: 2000 },
      cropDepthMm: 8500,
    },

    // Sheet + schedules.
    {
      type: 'upsertSheet',
      id: 'hf-sheet-ga01',
      name: 'GA-01 General arrangement',
      titleBlock: 'A2-bim-ai-default',
      paperWidthMm: 594,
      paperHeightMm: 420,
    },
    {
      type: 'upsertSchedule',
      id: 'hf-sch-rooms',
      name: 'Room schedule',
      sheetId: 'hf-sheet-ga01',
    },
    {
      type: 'upsertSchedule',
      id: 'hf-sch-windows',
      name: 'Window schedule',
      sheetId: 'hf-sheet-ga01',
    },
    {
      type: 'upsertSchedule',
      id: 'hf-sch-doors',
      name: 'Door schedule',
      sheetId: 'hf-sheet-ga01',
    },
  ];
}

