content = r'''/** @typedef {Record<string, unknown>} BimCommand */

/*
 * Canonical seed: the demo "one-family home" project.
 *
 * Authored phase-by-phase per `claude-skills/sketch-to-bim/SKILL.md`.
 * Reference spec: `spec/target-house-seed.md`.
 * Visual ground-truth: `spec/target-house-seed-vis.png` (line sketch)
 *                      `spec/target-house-vis-colored.png` (colour study, 4 panels).
 *
 * Coordinate convention (plan):
 *   +xMm = east, +yMm = north (south facade sits at y = 0)
 *   zMm / levelElevation = height above ground slab
 */

// ── Dimensional constants ─────────────────────────────────────────────
const GF_W = 7000; // ground-floor east-west width
const GF_D = 8000; // building depth north-south (both floors)
const UF_W = 5000; // upper-floor east-west width (west-aligned)
const F2F = 3000; // floor-to-floor height (ground → upper)
const WALL_T = 250; // exterior wall thickness

// Near-symmetric asymmetric gable — ridge at 60 % of UF width from west
// (spec §1.2 "roughly 60 % of the upper-volume width from the west edge").
// West eave slightly lower than east; both pitches similar (~25–30°).
const EAVE_W = 1500; // west (low) eave height above UF slab, mm
const EAVE_E = 2300; // east (high) eave height above UF slab, mm
const RIDGE_OFFS = 500; // ridge X-offset east of UF centre → x = 3 000 mm from west

// Computed gable geometry (ridgeAlongX = false — UF is 5 000 < 8 000 mm depth):
//   leftRun  = UF_W/2 + RIDGE_OFFS = 3 000 mm  (west edge → ridge)
//   RIDGE_H  = EAVE_W + leftRun · tan(30°) = 1 500 + 1 732 = 3 232 mm above UF
//   rightRun = UF_W/2 − RIDGE_OFFS = 2 000 mm  (ridge → east edge)
//   eastPitch = atan(932 / 2 000) ≈ 25°   (west 30°, east 25° — near-symmetric ✓)
const SLOPE_DEG = 30;
const LEFT_RUN = UF_W / 2 + RIDGE_OFFS; // 3 000 mm
const RIDGE_H = Math.round(EAVE_W + LEFT_RUN * Math.tan((SLOPE_DEG * Math.PI) / 180)); // 3 232 mm

// Absolute Z coordinates (above ground slab = 0)
const UF_Z = F2F; // 3 000 mm
const EAVE_W_Z = UF_Z + EAVE_W; // 4 500 mm  (west eave absolute)
const EAVE_E_Z = UF_Z + EAVE_E; // 5 300 mm  (east eave absolute)
const RIDGE_Z = UF_Z + RIDGE_H; // 6 232 mm  (ridge absolute)
const RIDGE_X = UF_W / 2 + RIDGE_OFFS; // 3 000 mm from west edge

// UF wall height before roof-attachment crop. Must exceed RIDGE_H; 3 800 mm
// is ridge + 568 mm headroom — walls get cropped to the gable profile.
const UF_WALL_H = RIDGE_H + 568; // 3 800 mm

const PARAPET_H = 200; // east deck parapet height above UF slab
const LOGGIA_SETBACK = 1500; // loggia recess depth south → north (spec §1.4 ~1 500 mm)
const BALCONY_PROJ = 650; // balcony projection south of facade plane (spec §1.4 "very slightly")

/**
 * @returns {BimCommand[]}
 */
export function buildOneFamilyHomeCommands() {
  return [
    // ── Project base point + levels ───────────────────────────────────
    {
      type: 'createProjectBasePoint',
      id: 'hf-pbp',
      positionMm: { xMm: 0, yMm: 0, zMm: 0 },
      angleToTrueNorthDeg: 0,
    },
    { type: 'createLevel', id: 'hf-lvl-ground', name: 'Ground Floor', elevationMm: 0 },
    { type: 'createLevel', id: 'hf-lvl-upper', name: 'First Floor', elevationMm: F2F },

    // === PHASE 1: MASSING ===
    // Three volumetric blocks — ground floor base (7 000 × 8 000), upper
    // west-aligned volume (5 000 × 8 000), and the east-deck parapet strip
    // (2 000 × 8 000). Deleted at the start of Phase 2 (mass-box roofs at
    // z = 3 000 would z-fight the upper-floor + deck slabs).
    {
      type: 'createMass',
      id: 'hf-mass-gf',
      name: 'Ground floor mass',
      levelId: 'hf-lvl-ground',
      footprintMm: [
        { xMm: 0, yMm: 0 },
        { xMm: GF_W, yMm: 0 },
        { xMm: GF_W, yMm: GF_D },
        { xMm: 0, yMm: GF_D },
      ],
      heightMm: F2F,
      materialKey: 'cladding_beige_grey',
    },
    {
      type: 'createMass',
      id: 'hf-mass-uf',
      name: 'Upper floor mass (west-aligned)',
      levelId: 'hf-lvl-upper',
      footprintMm: [
        { xMm: 0, yMm: 0 },
        { xMm: UF_W, yMm: 0 },
        { xMm: UF_W, yMm: GF_D },
        { xMm: 0, yMm: GF_D },
      ],
      heightMm: EAVE_E,
      materialKey: 'white_render',
    },
    {
      type: 'createMass',
      id: 'hf-mass-parapet',
      name: 'East deck parapet mass',
      levelId: 'hf-lvl-upper',
      footprintMm: [
        { xMm: UF_W, yMm: 0 },
        { xMm: GF_W, yMm: 0 },
        { xMm: GF_W, yMm: GF_D },
        { xMm: UF_W, yMm: GF_D },
      ],
      heightMm: PARAPET_H,
      materialKey: 'cladding_beige_grey',
    },

    // === PHASE 2: SKELETON ===
    // Delete Phase 1 masses, build load-bearing structural primitives:
    // perimeter walls at every level + floor slabs + flat-roof placeholder.
    { type: 'deleteElement', elementId: 'hf-mass-gf' },
    { type: 'deleteElement', elementId: 'hf-mass-uf' },
    { type: 'deleteElement', elementId: 'hf-mass-parapet' },

    // Ground-floor perimeter walls (height = F2F, CCW from SW corner).
    {
      type: 'createWall',
      id: 'hf-w-gf-s',
      name: 'GF south wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: 0, yMm: 0 },
      end: { xMm: GF_W, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: F2F,
    },
    {
      type: 'createWall',
      id: 'hf-w-gf-e',
      name: 'GF east wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: GF_W, yMm: 0 },
      end: { xMm: GF_W, yMm: GF_D },
      thicknessMm: WALL_T,
      heightMm: F2F,
    },
    {
      type: 'createWall',
      id: 'hf-w-gf-n',
      name: 'GF north wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: GF_W, yMm: GF_D },
      end: { xMm: 0, yMm: GF_D },
      thicknessMm: WALL_T,
      heightMm: F2F,
    },
    {
      type: 'createWall',
      id: 'hf-w-gf-w',
      name: 'GF west wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: 0, yMm: GF_D },
      end: { xMm: 0, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: F2F,
    },

    // Upper-floor perimeter walls (5 000 × 8 000, west-aligned).
    // heightMm = UF_WALL_H (ridge + margin) — Phase 3 crops to the
    // asymmetric gable profile via attachWallTopToRoof.
    {
      type: 'createWall',
      id: 'hf-w-uf-s',
      name: 'UF south wall',
      levelId: 'hf-lvl-upper',
      start: { xMm: 0, yMm: 0 },
      end: { xMm: UF_W, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: UF_WALL_H,
    },
    {
      type: 'createWall',
      id: 'hf-w-uf-e',
      name: 'UF east wall',
      levelId: 'hf-lvl-upper',
      start: { xMm: UF_W, yMm: 0 },
      end: { xMm: UF_W, yMm: GF_D },
      thicknessMm: WALL_T,
      heightMm: UF_WALL_H,
    },
    {
      type: 'createWall',
      id: 'hf-w-uf-n',
      name: 'UF north wall',
      levelId: 'hf-lvl-upper',
      start: { xMm: UF_W, yMm: GF_D },
      end: { xMm: 0, yMm: GF_D },
      thicknessMm: WALL_T,
      heightMm: UF_WALL_H,
    },
    {
      type: 'createWall',
      id: 'hf-w-uf-w',
      name: 'UF west wall',
      levelId: 'hf-lvl-upper',
      start: { xMm: 0, yMm: GF_D },
      end: { xMm: 0, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: UF_WALL_H,
    },

    // East deck parapet walls (S / E / N — west edge butts UF east wall).
    {
      type: 'createWall',
      id: 'hf-w-pa-s',
      name: 'Deck parapet south',
      levelId: 'hf-lvl-upper',
      start: { xMm: UF_W, yMm: 0 },
      end: { xMm: GF_W, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: PARAPET_H,
    },
    {
      type: 'createWall',
      id: 'hf-w-pa-e',
      name: 'Deck parapet east',
      levelId: 'hf-lvl-upper',
      start: { xMm: GF_W, yMm: 0 },
      end: { xMm: GF_W, yMm: GF_D },
      thicknessMm: WALL_T,
      heightMm: PARAPET_H,
    },
    {
      type: 'createWall',
      id: 'hf-w-pa-n',
      name: 'Deck parapet north',
      levelId: 'hf-lvl-upper',
      start: { xMm: GF_W, yMm: GF_D },
      end: { xMm: UF_W, yMm: GF_D },
      thicknessMm: WALL_T,
      heightMm: PARAPET_H,
    },

    // Floor slabs.
    {
      type: 'createFloor',
      id: 'hf-flr-ground',
      name: 'Ground floor slab',
      levelId: 'hf-lvl-ground',
      boundaryMm: [
        { xMm: 0, yMm: 0 },
        { xMm: GF_W, yMm: 0 },
        { xMm: GF_W, yMm: GF_D },
